let nextId = 1;
let nextLink = 1;
const nodes = [];
const links = [];
function node(type, pos, size, widgets_values=[], title=null) {
  const n = { id: nextId++, type, pos, size, flags: {}, order: 0, mode: 0, inputs: [], outputs: [], properties: {"Node name for S&R": type}, widgets_values };
  if (title) n.title = title;
  nodes.push(n);
  return n;
}
function out(n, name, type, slot=0) {
  const o = { name, type, links: [], slot_index: slot };
  n.outputs.push(o);
  return slot;
}
function input(n, name, type, link=null) {
  n.inputs.push({ name, type, link });
  return n.inputs.length - 1;
}
function link(from, fromSlot, to, toSlot, type) {
  const id = nextLink++;
  links.push([id, from.id, fromSlot, to.id, toSlot, type]);
  from.outputs[fromSlot].links ??= [];
  from.outputs[fromSlot].links.push(id);
  to.inputs[toSlot].link = id;
  return id;
}

const expressions = [
  ['smile', 'gentle smile, warm eyes, relaxed mouth, approachable heroine expression'],
  ['shy', 'shy blush, slightly averted eyes, timid smile, bashful expression'],
  ['happy', 'bright happy smile, sparkling eyes, open cheerful expression'],
  ['sad', 'sad expression, watery eyes, small frown, delicate melancholy mood'],
  ['angry', 'angry expression, determined eyes, furrowed brows, tense mouth'],
  ['surprised', 'surprised expression, wide eyes, parted lips, startled but cute']
];
const actions = [
  ['standing_front', 'pose_standing_front.png', 'standing front, neutral full body visual novel sprite pose'],
