  ['one_hand_up', 'pose_one_hand_up.png', 'one hand raised, greeting or explaining pose'],
  ['arms_crossed', 'pose_arms_crossed.png', 'arms crossed, confident pose'],
  ['looking_back', 'pose_looking_back.png', 'looking back over shoulder, dynamic pose'],
  ['sitting', 'pose_sitting.png', 'sitting pose, visual novel event sprite pose']
];

const ckpt = node('CheckpointLoaderSimple', [-1320, -40], [315,98], ['PUT_ANIME_CHECKPOINT_HERE.safetensors'], 'Anime checkpoint');
out(ckpt,'MODEL','MODEL',0); out(ckpt,'CLIP','CLIP',1); out(ckpt,'VAE','VAE',2);

const anchor = node('LoadImage', [-1320, 150], [315,314], ['character_anchor.png','image'], 'Character anchor image');
out(anchor,'IMAGE','IMAGE',0); out(anchor,'MASK','MASK',1); anchor.outputs[0].shape=3; anchor.outputs[1].shape=3; anchor.outputs[1].links=null;

const ipaLoad = node('IPAdapterUnifiedLoader', [-940, 180], [315,78], ['PLUS FACE (portraits)'], 'IP-Adapter loader');
