input(neg,'clip','CLIP'); out(neg,'CONDITIONING','CONDITIONING',0); link(ckpt,1,neg,0,'CLIP');

const latent = node('EmptyLatentImage', [-560, -90], [315,106], [768,1152,1], 'VN sprite canvas 768x1152');
out(latent,'LATENT','LATENT',0);

const exprNodes = [];
for (let i=0;i<expressions.length;i++) {
  const [key, expr] = expressions[i];
  const text = `masterpiece, best quality, clean anime visual novel character sprite, single girl, solo, full body, centered character, transparent-background-friendly plain light background, consistent character design from reference, same hairstyle, same face tendency, same outfit motif, ${expr}`;
  const e = node('CLIPTextEncode', [-1320, 720 + i*220], [500,180], [text], `Expression ${i+1}: ${key}`);
  input(e,'clip','CLIP'); out(e,'CONDITIONING','CONDITIONING',0); link(ckpt,1,e,0,'CLIP'); exprNodes.push(e);
}

const actionPre = [];
for (let a=0;a<actions.length;a++) {
