  const load = node('LoadImage', [-720, 720 + a*250], [260,220], [file,'image'], `Pose ${a+1}: ${key}`);
  out(load,'IMAGE','IMAGE',0); out(load,'MASK','MASK',1); load.outputs[0].shape=3; load.outputs[1].shape=3; load.outputs[1].links=null;
  const pre = node('OpenposePreprocessor', [-400, 720 + a*250], [315,150], ['enable','enable','enable',1024,'disable'], `OpenPose ${a+1}: ${key}`);
  input(pre,'image','IMAGE'); out(pre,'IMAGE','IMAGE',0); pre.outputs[0].shape=3;
  link(load,0,pre,0,'IMAGE'); actionPre.push({key,file,desc,pre});
}

let x0 = 80, y0 = 720;
