    const ks = node('KSampler', [x+360, y], [315,262], [1000000 + a*100 + e, 'randomize', 26, 6.5, 'dpmpp_2m', 'karras', 1], `Sample ${exprKey} + ${actKey}`);
    input(ks,'model','MODEL'); input(ks,'positive','CONDITIONING'); input(ks,'negative','CONDITIONING'); input(ks,'latent_image','LATENT'); out(ks,'LATENT','LATENT',0);
    link(ipa,0,ks,0,'MODEL'); link(c,0,ks,1,'CONDITIONING'); link(c,1,ks,2,'CONDITIONING'); link(latent,0,ks,3,'LATENT');
    const vae = node('VAEDecode', [x+710, y], [210,46], [], `Decode ${exprKey} + ${actKey}`);
    input(vae,'samples','LATENT'); input(vae,'vae','VAE'); out(vae,'IMAGE','IMAGE',0);
    link(ks,0,vae,0,'LATENT'); link(ckpt,2,vae,1,'VAE');
    const save = node('SaveImage', [x+710, y+90], [315,58], [`vn_diffs/${exprKey}_${actKey}`], `Save ${exprKey} + ${actKey}`);
    input(save,'images','IMAGE'); link(vae,0,save,0,'IMAGE');
  }
}

nodes.forEach((n,i)=>n.order=i);
const groups = [
  {title:'1. Character anchor + model', bounding:[-1360,-180,1160,520], color:'#3f789e', font_size:24},
