  }
  if(-not $ready){ throw "ComfyUI server did not become ready. See $log and $err" }

  $prompt = @{
    prompt = @{
      '1' = @{ class_type='CheckpointLoaderSimple'; inputs=@{ ckpt_name='meinamix_v12Final.safetensors' } }
      '2' = @{ class_type='LoadImage'; inputs=@{ image='character/0d6c6a2e2f48c25dc4ca24ce6070383c.png' } }
      '3' = @{ class_type='CLIPTextEncode'; inputs=@{ clip=@('1',1); text='1girl, solo, beautiful anime girl, soft lighting, delicate hair, detailed eyes, subtle blush, clean lineart, smooth shading, romantic visual novel style, gentle expression' } }
