      '5' = @{ class_type='VAEEncode'; inputs=@{ pixels=@('2',0); vae=@('1',2) } }
      '6' = @{ class_type='KSampler'; inputs=@{ model=@('1',0); positive=@('3',0); negative=@('4',0); latent_image=@('5',0); seed=123456789; steps=28; cfg=6.5; sampler_name='dpmpp_2m'; scheduler='karras'; denoise=0.45 } }
      '7' = @{ class_type='VAEDecode'; inputs=@{ samples=@('6',0); vae=@('1',2) } }
      '8' = @{ class_type='SaveImage'; inputs=@{ images=@('7',0); filename_prefix='basic_img2img_character_api' } }
    }
  }
